import{o as e,c as m,C as p}from"./framework.5e85cea8.js";const t='{"title":"Глава 4","description":"","frontmatter":{"title":"Глава 4","subtitle":"Малини виджайоттара тантра","tags":"malini","date":"2020-10-20T00:00:00.000Z"},"relativePath":"texts/malini-vijayottara/4.md","lastUpdated":1624912574007}',a={},_=p('<div class="stanza"><div id="s4.1" class="num">4.1</div><p>Услышав это, мудрецы, победившие гнев с обрадованным взором, поклонившись вновь, сказали такие слова.</p></div><p>Какова цель пробуждения мантры на пути йоги, о которой вопрошала Деви у Верховного Владыки, и каков Его ответ, бездонный как колодец?.2.</p><p>На сказанное (ими всеми) вместе, великий мудрец Карттикея ради прекращения воплощенности сказал такую речь ..3.</p><p>Йога, (которая есть) желанное Единство, есть Реальность, отличная от (этой) реальности. То, что является Реальностью, именуется Постигаемым ради обретения <em>данного</em> ..4.</p><p>Знание, без которого невозможно Постижение - двух видов. Ради его обретения, Шивой разъяснено это Знание ..5.</p><p>Ради обретения совершенства в йоге достаточно пробуждения мантры. Без дикши йога не применима, о Шанкари!.6.</p><p>Она именуется двоякой (йогой) как (йога) знания и действия. Двояко она выполняется и происходящее от этого двояко ..7.</p><p>Нет пригодности к йоге (если) нет стремления к Единству (с Божеством). Пригодность к мантре через Шива-дикшу (само по себе) - Освобождение ..8.</p><p>Услышав эти слова, Мать Парвати со вздыбленными волосками, трепещущим телом и слезами вновь обратилась с такой речью: О, лучшие мудрецы!.9.</p><p>В теле неделимой <em>малини</em> как было услышано (Мной), есть татвы, миры, пады, мантры ..10.</p><p>То, что является разделением йони, поведанное Мне Тобой, именуется _малини, _о Бог! Поведай о составных частях, пребывающих в ней ..11.</p><p>На речь, сказанную Великой Богиней, Бхайрава - Солнце (своим) простертым сиянием освещающее внутренне пространство (Сознания), Наделяющий многочисленным богатством, Носящий диадему, гирлянду богов и демонов, играючи наставляющий, невозмутимо сказал такие ласковые слова:.12-13.</p><p>То, что мной именуется разделенным йони - есть <em>малини</em>._ <em>Поведаю все</em> _об ее частях пребывающих (в ней) ..14.</p><p>В (слоге) ПХА пребывает элемент земли.(Остальные) двадцать три (таттвы) пребывают от ДА до ДЖХА и от БА до <em>прадханы</em>. Четырнадцать слогов начиная с ТХА - ( представляют слоги) начиная с <em>пуруши</em>. Триада И, ДА,_ _ГХА есть постигаемая <em>сакала</em> . В <em>Шива татве</em> выделяются шестнадцать (слогов) от ГА до НА. Выслушай о Прекрасная, как оно есть, о трех видах постигаемого, (описанного) ранее, подразделяемого по числу слогов на <em>калу</em>, <em>паду</em>, <em>мантру</em>, и <em>бхувану</em> ..15-18.</p><p>В <em>нишкала</em> (мантре)- односложная <em>пада</em>, трех и односложная. В <em>сакала</em> (мантре) - пяти, одно и двухсложная, четырехсложная, начиная с майи- двух и трехсложная. Четырехсложная (пада), одно и двухсложная- начиная с Кала (таттвы). В <em>раскрашивании</em> называется два слога, в <em>прадхане</em> - три слога, в <em>буддхи,</em> пронизанной восьмеркой богов, <em>пада</em> именуется двухсложной. Четыре пады у _видйа _(таттвы), вместе с половиной (слога)- пять. В <em>партхива таттве</em> - три: одна, одна и половина слога. В <em>пуруша (таттве)</em> и <em>рага (таттве)</em> (пребывают) все мысли, <em>варны</em>, <em>мантры</em>, <em>калА</em> и прочее. Два с половиной слога, (САУХ) пронизывающие по отдельности двоих по одному - это обратное проникновение именуется низшим (апара). Три вселенные пронизанные «трезубцем» (АУ) и четвертая (есть среднее, парапара). Высшим проникновением именуется проникновение через висаргу ..19-25.</p><p>Все это, постигаемое обретается йогином, желающим пользы себе и другим и не иначе ..26.</p><p>Джнана и йога- два вида постижения. Желающими результата они мыслятся по отдельности ..27.</p><p>Знание именуется трех видов: первое - слушание, затем - обдумывание, и созерцание ..28.</p><p>Знание смысла писаний, распространенное и услышанное мнение применяется так и эдак ..29.</p><p>Знание, состоящее из размышления, последовательно взирающее на все через сущность писаний, именуется двух видов ..30.</p><p>(Первое) - медленное, через различение своего «Я», в котором является осознавание собственного положения, (второе) - состояние <em>нишпанана</em>, при котором является <em>бхавана</em> ..31.</p><p>Затем йогин, пребывая в йоге, обретает результат йоги. Согласно четырем разновидностям знания, джнанин бывает четырех (видов) ..32.</p><p>(Это) - Достигнувший, разрушивший ум, совершенный и совершенийший. О Деви, также йогин именуется четырех видов ..33.</p><p>Йога именуемая <em>самавеша</em> бывает трех видов: та, наставление в которой обретается по линии преемствености, известна мудрым как обретенная йога трех видов. Воистину, кто снова и снова совершает разрушение беспокойства ума, к которому стремятся мудрые, достиг (состояния), когда сознание не опирается ни на что вторичное. Это именуется сиддха йога желающими успеха в йоге. Кто бы и где бы не пребывал, благодаря ей (он) насладится ее результатом, не иначе. Он - сиддха, он - просветленный, он подобен Садашиве, о Возлюбленная!.34-38.</p><p>Каждый последующий (из названых) джнанинов, йогинов и сиддхов и знающих йогу выше предыдущих ..39.</p><p>Тот, кто отбрасывает обретенный ранее результат йоги, именуется мудрыми дающим освобождение, знающим, пребывающим в знании собственного «Я» ..40.</p><p>Итак, Тебе поведано вкратце все о постигаемой сущности тантры для пользы йогинов ..41. [small]Такова в священной «Малини виджайоттара тантре» четвертая глава.[/small]</p>',27);a.render=function(p,t,a,i,s,l){return e(),m("div",null,[_])};export default a;export{t as __pageData};
